// telegra.ph URL path (decoded, lowercased) -> logical content id.
const URL_PATH_TO_ID: Record<string, string> = {
  "-08-06-2817": "hotels",
  "crypto-investment-guide-06-03": "crypto",
  "𝗥𝗲𝗳𝘂𝗻𝗱𝘀-for-your-sportsconcertmusical-events---𝗪𝗼𝗿𝗹𝗱𝘄𝗶𝗱𝗲-01-31": "viator"
};

// Stores with an info popup but NO inline link in their notes, matched by domain.
const DOMAIN_TO_ID: Record<string, string> = {
  "stubhub.com": "stubhub"
};

/** Normalize any telegra.ph URL to its path key (decoded, lowercased). */
function telegraphKeyFromUrl(url: string): string | null {
  try {
    const u = new URL(url);
    if (!/(^|\.)telegra\.ph$/i.test(u.hostname)) return null;
    return decodeURIComponent(u.pathname).replace(/^\/+/, "").toLowerCase();
  } catch {
    return null;
  }
}

/** Recreated content for a telegra.ph URL found in a store note, or null. */
export function getTelegraphContent(url: string): TelegraphContent | null {
  const k = telegraphKeyFromUrl(url);
  if (!k) return null;
  const id = URL_PATH_TO_ID[k];
  return id ? INFO_CONTENT[id] ?? null : null;
}

/** Recreated content for a store that has no inline link, matched by domain. */
export function getStoreInfoByDomain(domain: string | null | undefined): TelegraphContent | null {
  if (!domain) return null;
  const key = domain.trim().toLowerCase().replace(/^www\./, "");
  const id = DOMAIN_TO_ID[key];
  return id ? INFO_CONTENT[id] ?? null : null;
}
